import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { toast } from "react-toastify";
import Modal from "../components/Modal";
import { logout } from "../authReducer"; // Импортируем logout

function Admin() {
  const [users, setUsers] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [userToBan, setUserToBan] = useState(null);
  const [roleChanges, setRoleChanges] = useState({}); // Состояние для отслеживания изменений ролей
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();

  useEffect(() => {
    fetch("http://localhost:3001/users")
      .then((res) => res.json())
      .then((data) => setUsers(data))
      .catch((error) => toast.error("Ошибка загрузки пользователей"));
  }, []);

  async function handleBanToggle(userId, isBanned) {
    try {
      const response = await fetch(`http://localhost:3001/users/${userId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ isBanned: !isBanned }),
      });
      if (response.ok) {
        setUsers(users.map((u) => (u.id === userId ? { ...u, isBanned: !isBanned } : u)));
        toast.success(`Пользователь ${isBanned ? "разбанен" : "заблокирован"}!`);

        // Если банят текущего пользователя, разлогиниваем его
        if (parseInt(userId) === parseInt(user.id) && !isBanned) {
          dispatch(logout());
          toast.info("Вы были заблокированы и вышли из системы.");
        }
      } else {
        toast.error("Не удалось изменить статус");
      }
    } catch (error) {
      toast.error("Сетевая ошибка");
    }
    setIsModalOpen(false);
  }

  function openModal(userId) {
    setUserToBan(userId);
    setIsModalOpen(true);
  }

  async function handleRoleChange(userId, newRole) {
    // Проверяем, сколько уже есть администраторов
    const adminResponse = await fetch(`http://localhost:3001/users?role=admin`);
    const admins = await adminResponse.json();
    const adminLimit = 2;

    // Если пытаемся назначить новую роль admin и лимит превышен
    if (newRole === "admin" && admins.length >= adminLimit && !admins.some((admin) => parseInt(admin.id) === parseInt(userId))) {
      toast.error(`Лимит администраторов (${adminLimit}) достигнут. Нельзя назначить больше администраторов.`);
      return;
    }

    try {
      const response = await fetch(`http://localhost:3001/users/${userId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ role: newRole }),
      });

      if (response.ok) {
        setUsers(users.map((u) => (u.id === userId ? { ...u, role: newRole } : u)));
        setRoleChanges((prev) => {
          const updated = { ...prev };
          delete updated[userId]; // Удаляем изменение из состояния после сохранения
          return updated;
        });
        toast.success(`Роль пользователя изменена на ${newRole}!`);

        // Если роль текущего пользователя изменили, разлогиниваем его
        if (parseInt(userId) === parseInt(user.id)) {
          dispatch(logout());
          toast.info("Ваша роль была изменена. Пожалуйста, войдите снова.");
        }
      } else {
        toast.error("Не удалось изменить роль");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при изменении роли");
    }
  }

  function handleRoleSelect(userId, selectedRole) {
    setRoleChanges((prev) => ({
      ...prev,
      [userId]: selectedRole,
    }));
  }

  if (user?.role !== "admin") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="mb-4">Панель администратора</h1>
      <ul className="list-group">
        {users.map((u) => (
          <li key={u.id} className="list-group-item d-flex justify-content-between align-items-center">
            <div>
              <span>
                {u.name} ({u.email}) - {u.role} {u.isBanned && <span className="text-danger">[Заблокирован]</span>}
              </span>
              <div className="mt-2">
                <label htmlFor={`role-${u.id}`} className="form-label me-2">
                  Изменить роль:
                </label>
                <select
                  id={`role-${u.id}`}
                  className="form-select d-inline-block w-auto"
                  value={roleChanges[u.id] || u.role}
                  onChange={(e) => handleRoleSelect(u.id, e.target.value)}
                >
                  <option value="student">Студент</option>
                  <option value="teacher">Преподаватель</option>
                  <option value="admin">Администратор</option>
                </select>
                {roleChanges[u.id] && roleChanges[u.id] !== u.role && (
                  <button
                    onClick={() => handleRoleChange(u.id, roleChanges[u.id])}
                    className="btn btn-primary btn-sm ms-2"
                  >
                    Сохранить
                  </button>
                )}
              </div>
            </div>
            <button
              onClick={() => openModal(u.id)}
              className={`btn ${u.isBanned ? "btn-success" : "btn-danger"} btn-sm`}
            >
              {u.isBanned ? "Разбанить" : "Забанить"}
            </button>
          </li>
        ))}
      </ul>
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onConfirm={() => handleBanToggle(userToBan, users.find((u) => u.id === userToBan)?.isBanned)}
        message={`Вы уверены, что хотите ${
          users.find((u) => u.id === userToBan)?.isBanned ? "разбанить" : "забанить"
        } этого пользователя?`}
      />
    </div>
  );
}

export default Admin;
